evaluators.evaluation_logic:
const checkpoints = [];

const applications = JSON.parse(localStorage.getItem('applications') || '[]');
const preferences = JSON.parse(localStorage.getItem('application_nursery_preferences') || '[]');
const nurseries = JSON.parse(localStorage.getItem('nurseries') || '[]');
const feeSchedules = JSON.parse(localStorage.getItem('nursery_fee_schedules') || '[]');

function getDateOnly(str) {
  if (!str) return '';
  if (/^\d{4}-\d{2}-\d{2}$/.test(str)) return str;
  const d = new Date(str);
  if (isNaN(d.getTime())) return '';
  const y = d.getUTCFullYear();
  const m = String(d.getUTCMonth() + 1).padStart(2, '0');
  const day = String(d.getUTCDate()).padStart(2, '0');
  return y + '-' + m + '-' + day;
}

function parseDate(str) {
  if (!str) return null;
  const d = new Date(str);
  return isNaN(d.getTime()) ? null : d;
}

const desiredStartFrom = '2025-09-01';
const desiredStartTo = '2025-09-10'; // "early September" window
const childAgeYears = 3;
const childAgeMonths = Math.round(childAgeYears * 12);
const maxDistanceKm = 3;
const maxMonthlyFee = 600;

function estimateMonthlyFee(nurseryId, careType, childAgeYears, desiredStartDate) {
  const months = Math.round(childAgeYears * 12);
  const ref = parseDate(desiredStartDate);
  const relevant = feeSchedules.filter(s => {
    if (s.nurseryId !== nurseryId) return false;
    if (careType && s.careType !== careType) return false;
    if (typeof months === 'number') {
      if (typeof s.ageMinMonths === 'number' && months < s.ageMinMonths) return false;
      if (typeof s.ageMaxMonths === 'number' && months > s.ageMaxMonths) return false;
    }
    if (ref) {
      if (s.validFrom) {
        const vf = parseDate(s.validFrom);
        if (vf && ref < vf) return false;
      }
      if (s.validTo) {
        const vt = parseDate(s.validTo);
        if (vt && ref > vt) return false;
      }
    }
    return true;
  });
  if (!relevant.length) return null;
  let min = null;
  relevant.forEach(s => {
    if (typeof s.monthlyFee === 'number') {
      if (min === null || s.monthlyFee < min) min = s.monthlyFee;
    }
  });
  return min;
}

function nurseryMeetsCriteria(n) {
  if (!n) return false;
  if (typeof n.distanceFromHomeKm !== 'number' || n.distanceFromHomeKm > maxDistanceKm) return false;
  if (!n.hasFullDayCare) return false;
  if (typeof n.acceptedAgeMinMonths === 'number' && childAgeMonths < n.acceptedAgeMinMonths) return false;
  if (typeof n.acceptedAgeMaxMonths === 'number' && childAgeMonths > n.acceptedAgeMaxMonths) return false;
  const fee = estimateMonthlyFee(n.id, 'full_day_8h_plus', childAgeYears, desiredStartFrom) ?? (typeof n.baseMonthlyFee === 'number' ? n.baseMonthlyFee : null);
  if (fee === null || fee > maxMonthlyFee) return false;
  return true;
}

// All qualifying nurseries and cheapest among them
const qualifyingNurseries = nurseries.filter(n => nurseryMeetsCriteria(n));
let cheapestFee = null;
const feeByNursery = {};
qualifyingNurseries.forEach(n => {
  const fee = estimateMonthlyFee(n.id, 'full_day_8h_plus', childAgeYears, desiredStartFrom) ?? n.baseMonthlyFee;
  feeByNursery[n.id] = fee;
  if (typeof fee === 'number') {
    if (cheapestFee === null || fee < cheapestFee) cheapestFee = fee;
  }
});
const cheapestNurseryIds = qualifyingNurseries.filter(n => feeByNursery[n.id] === cheapestFee).map(n => n.id);

// Candidate applications: full-day, early September 2025
const candidateApps = applications.filter(app => {
  if (!app || app.careType !== 'full_day_8h_plus') return false;
  const d = getDateOnly(app.desiredStartDate);
  if (!d) return false;
  return d >= desiredStartFrom && d <= desiredStartTo;
});

// CP1 (0.30): At least one full-day application starting in early Sept 2025 with any nursery preference
let cp1Passed = false;
for (const app of candidateApps) {
  const appPrefs = preferences.filter(p => p.applicationId === app.id);
  if (appPrefs.length > 0) {
    cp1Passed = true;
    break;
  }
}
checkpoints.push({ passed: cp1Passed, weight: 0.30 });

// CP2 (0.30): There exists such an application where ALL its preferred nurseries meet distance, age, and fee criteria
let cp2Passed = false;
for (const app of candidateApps) {
  const appPrefs = preferences.filter(p => p.applicationId === app.id);
  if (!appPrefs.length) continue;
  const allQualifying = appPrefs.every(p => {
    const n = nurseries.find(nn => nn.id === p.nurseryId);
    return nurseryMeetsCriteria(n);
  });
  if (allQualifying) {
    cp2Passed = true;
    break;
  }
}
checkpoints.push({ passed: cp2Passed, weight: 0.30 });

// CP3 (0.40): There exists such an application with exactly ONE preference and that nursery is the cheapest qualifying nursery overall
let cp3Passed = false;
if (cheapestNurseryIds.length > 0) {
  for (const app of candidateApps) {
    const appPrefs = preferences.filter(p => p.applicationId === app.id);
    if (appPrefs.length !== 1) continue;
    const prefNurseryId = appPrefs[0].nurseryId;
    if (cheapestNurseryIds.includes(prefNurseryId)) {
      cp3Passed = true;
      break;
    }
  }
}
checkpoints.push({ passed: cp3Passed, weight: 0.40 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const favorites = JSON.parse(localStorage.getItem('favorite_nurseries') || '[]');
const nurseries = JSON.parse(localStorage.getItem('nurseries') || '[]');

function isQualifyingNursery(n) {
  if (!n) return false;
  if (n.district !== 'downtown') return false;
  if (typeof n.ratingAverage !== 'number' || n.ratingAverage < 4.5) return false;
  if (!n.opensByTimeWeekday) return false;
  if (n.opensByTimeWeekday > '07:00') return false; // opens by 07:00 or earlier
  return true;
}

// All qualifying nurseries in the dataset
const qualifyingNurseries = nurseries.filter(isQualifyingNursery);

// All favorites that point to qualifying nurseries
const qualifyingFavoriteNurseryIds = favorites
  .map(f => f && f.nurseryId)
  .filter(id => {
    const n = nurseries.find(nn => nn.id === id);
    return isQualifyingNursery(n);
  });

// CP1 (0.40): User has favorited at least one nursery that meets the Downtown, rating, and opening-time criteria
const cp1Passed = qualifyingFavoriteNurseryIds.length > 0;
checkpoints.push({ passed: cp1Passed, weight: 0.40 });

// Find earliest opening time among all qualifying nurseries
let earliestTime = null;
if (qualifyingNurseries.length > 0) {
  qualifyingNurseries.forEach(n => {
    if (!n.opensByTimeWeekday) return;
    if (earliestTime === null || n.opensByTimeWeekday < earliestTime) {
      earliestTime = n.opensByTimeWeekday;
    }
  });
}
const earliestNurseryIds = qualifyingNurseries
  .filter(n => n.opensByTimeWeekday === earliestTime)
  .map(n => n.id);

// CP2 (0.60): Among qualifying nurseries, the user has favorited one of the earliest-opening ones
let cp2Passed = false;
if (earliestNurseryIds.length > 0) {
  cp2Passed = qualifyingFavoriteNurseryIds.some(id => earliestNurseryIds.includes(id));
}
checkpoints.push({ passed: cp2Passed, weight: 0.60 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const bookings = JSON.parse(localStorage.getItem('visit_bookings') || '[]');
const slots = JSON.parse(localStorage.getItem('visit_slots') || '[]');
const nurseries = JSON.parse(localStorage.getItem('nurseries') || '[]');

function getDateOnly(str) {
  if (!str) return '';
  if (/^\d{4}-\d{2}-\d{2}$/.test(str)) return str;
  const d = new Date(str);
  if (isNaN(d.getTime())) return '';
  const y = d.getUTCFullYear();
  const m = String(d.getUTCMonth() + 1).padStart(2, '0');
  const day = String(d.getUTCDate()).padStart(2, '0');
  return y + '-' + m + '-' + day;
}

// System date is 2026-03-03 (Tuesday); next Wednesday is 2026-03-04
const nextWednesday = '2026-03-04';
const windowStart = '09:00';
const windowEnd = '11:00';

const childAgeMonths = Math.round(2 * 12); // 2-year-old
const maxDistanceKm = 2;
const maxMonthlyFee = 550; // use baseMonthlyFee as in searchNurseriesForVisit

function nurseryMeetsVisitCriteria(n) {
  if (!n) return false;
  if (typeof n.distanceFromHomeKm !== 'number' || n.distanceFromHomeKm > maxDistanceKm) return false;
  if (!n.hasLargeOutdoorPlayground) return false;
  if (typeof n.acceptedAgeMinMonths === 'number' && childAgeMonths < n.acceptedAgeMinMonths) return false;
  if (typeof n.acceptedAgeMaxMonths === 'number' && childAgeMonths > n.acceptedAgeMaxMonths) return false;
  if (typeof n.baseMonthlyFee !== 'number' || n.baseMonthlyFee > maxMonthlyFee) return false;
  return true;
}

function bookingInTimeWindow(booking) {
  if (!booking) return false;
  const slot = slots.find(s => s.id === booking.visitSlotId);
  let dateOnly;
  let startTime;
  if (slot) {
    dateOnly = getDateOnly(slot.date);
    startTime = slot.startTime || null;
  } else {
    dateOnly = getDateOnly(booking.visitDateTime);
    startTime = booking.visitDateTime ? booking.visitDateTime.substring(11, 16) : null;
  }
  if (dateOnly !== nextWednesday || !startTime) return false;
  return startTime >= windowStart && startTime < windowEnd;
}

function nurseryHasAvailableSlotInWindow(nurseryId) {
  return slots.some(s => {
    if (s.nurseryId !== nurseryId) return false;
    if (s.isBooked) return false; // availability
    const d = getDateOnly(s.date);
    if (d !== nextWednesday) return false;
    const st = s.startTime || '';
    return st >= windowStart && st < windowEnd;
  });
}

// Nurseries that meet fee/distance/playground/age criteria
const candidateNurseries = nurseries.filter(n => nurseryMeetsVisitCriteria(n));

// Among those, nurseries that currently have an available slot in the desired window
const availableNurseries = candidateNurseries.filter(n => nurseryHasAvailableSlotInWindow(n.id));

let topRating = null;
availableNurseries.forEach(n => {
  if (typeof n.ratingAverage === 'number') {
    if (topRating === null || n.ratingAverage > topRating) topRating = n.ratingAverage;
  }
});
const topNurseryIds = availableNurseries
  .filter(n => typeof n.ratingAverage === 'number' && n.ratingAverage === topRating)
  .map(n => n.id);

// New bookings created via BusinessLogic.createVisitBooking (id starts with 'visit_booking_')
const newBookings = bookings.filter(b => typeof b.id === 'string' && b.id.indexOf('visit_booking_') === 0);

// Bookings that match all nursery constraints and the time window
const qualifyingBookings = newBookings.filter(b => {
  const n = nurseries.find(nn => nn.id === b.nurseryId);
  if (!nurseryMeetsVisitCriteria(n)) return false;
  if (!bookingInTimeWindow(b)) return false;
  return true;
});

// CP1 (0.40): User created a new booking next Wednesday between 09:00-11:00 at a nursery that meets distance, fee, age, and playground criteria
const cp1Passed = qualifyingBookings.length > 0;
checkpoints.push({ passed: cp1Passed, weight: 0.40 });

// CP2 (0.60): That booking is for one of the highest-rated nurseries (among those with an available slot in that window)
let cp2Passed = false;
if (topNurseryIds.length > 0) {
  cp2Passed = qualifyingBookings.some(b => topNurseryIds.includes(b.nurseryId));
}
checkpoints.push({ passed: cp2Passed, weight: 0.60 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const lists = JSON.parse(localStorage.getItem('activity_registration_lists') || '[]');
const items = JSON.parse(localStorage.getItem('activity_registration_items') || '[]');
const activities = JSON.parse(localStorage.getItem('activities') || '[]');

function getDateOnly(str) {
  if (!str) return '';
  if (/^\d{4}-\d{2}-\d{2}$/.test(str)) return str;
  const d = new Date(str);
  if (isNaN(d.getTime())) return '';
  const y = d.getUTCFullYear();
  const m = String(d.getUTCMonth() + 1).padStart(2, '0');
  const day = String(d.getUTCDate()).padStart(2, '0');
  return y + '-' + m + '-' + day;
}

function isQualifyingActivity(a) {
  if (!a) return false;
  const dateStr = getDateOnly(a.date);
  if (!dateStr.startsWith('2025-07')) return false; // July 2025
  if (a.timeOfDay !== 'afternoon') return false;
  if (typeof a.pricePerSession !== 'number' || a.pricePerSession > 30) return false;
  // Age overlap with 4–5 years
  if (typeof a.ageMinYears !== 'number' || typeof a.ageMaxYears !== 'number') return false;
  const minFilter = 4;
  const maxFilter = 5;
  const overlaps = a.ageMinYears <= maxFilter && a.ageMaxYears >= minFilter;
  return overlaps;
}

// Build, for each list, the qualifying registration items
const listsWithQualifying = lists.map(list => {
  const itemsForList = items.filter(i => i.registrationListId === list.id);
  const qualifyingItems = itemsForList.filter(i => {
    const a = activities.find(act => act.id === i.activityId);
    return isQualifyingActivity(a);
  });
  return { list, qualifyingItems };
});

// CP1 (0.20): At least one registration list has at least one qualifying July 2025 afternoon activity for 4–5-year-olds under 30 added
const cp1Passed = listsWithQualifying.some(entry => entry.qualifyingItems.length >= 1);
checkpoints.push({ passed: cp1Passed, weight: 0.20 });

// CP2 (0.30): At least one registration list has at least two DIFFERENT qualifying activities (any centers)
let cp2Passed = false;
for (const entry of listsWithQualifying) {
  const ids = entry.qualifyingItems.map(i => i.activityId);
  const uniqueIds = Array.from(new Set(ids));
  if (uniqueIds.length >= 2) {
    cp2Passed = true;
    break;
  }
}
checkpoints.push({ passed: cp2Passed, weight: 0.30 });

// CP3 (0.50): In at least one registration list, there are two different qualifying activities at the SAME center
let cp3Passed = false;
for (const entry of listsWithQualifying) {
  if (entry.qualifyingItems.length < 2) continue;
  const centerToActivities = {};
  for (const regItem of entry.qualifyingItems) {
    const a = activities.find(act => act.id === regItem.activityId);
    if (!a || !a.centerId) continue;
    if (!centerToActivities[a.centerId]) centerToActivities[a.centerId] = new Set();
    centerToActivities[a.centerId].add(a.id);
  }
  const hasCenterWithTwo = Object.values(centerToActivities).some(set => set.size >= 2);
  if (hasCenterWithTwo) {
    cp3Passed = true;
    break;
  }
}
checkpoints.push({ passed: cp3Passed, weight: 0.50 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const plans = JSON.parse(localStorage.getItem('fee_plans') || '[]');

const incomeTarget = 3200;
const childAgeYears = 2;

function calculateFeeEstimate(householdMonthlyIncome, childAgeYears, scheduleType) {
  const income = typeof householdMonthlyIncome === 'number' ? householdMonthlyIncome : 0;
  let base;
  if (scheduleType === 'half_day_5_days') {
    base = 200;
  } else if (scheduleType === 'full_day_5_days') {
    base = 350;
  } else {
    base = 250;
  }
  const incomeComponent = income * 0.05;
  const ageFactor = typeof childAgeYears === 'number' ? Math.max(0, 3 - childAgeYears) * 10 : 0;
  let fee = Math.round(base + incomeComponent + ageFactor);
  if (fee < 50) fee = 50;
  return fee;
}

const halfFee = calculateFeeEstimate(incomeTarget, childAgeYears, 'half_day_5_days');
const fullFee = calculateFeeEstimate(incomeTarget, childAgeYears, 'full_day_5_days');
const cheaperSchedule = halfFee <= fullFee ? 'half_day_5_days' : 'full_day_5_days';
const cheaperFee = halfFee <= fullFee ? halfFee : fullFee;

// Plans matching the scenario (name, age, income approx 3200)
const relevantPlans = plans.filter(p => {
  if (!p || typeof p.name !== 'string') return false;
  if (p.name.trim() !== 'My chosen schedule') return false;
  if (p.childAgeYears !== childAgeYears) return false;
  if (typeof p.householdMonthlyIncome !== 'number') return false;
  // Allow small tolerance around 3200
  if (Math.abs(p.householdMonthlyIncome - incomeTarget) > 50) return false;
  return true;
});

// CP1 (0.40): User saved at least one plan named 'My chosen schedule' for a 2-year-old with income around 3200
const cp1Passed = relevantPlans.length > 0;
checkpoints.push({ passed: cp1Passed, weight: 0.40 });

// CP2 (0.60): Among those, at least one plan uses the cheaper schedule type with the corresponding (or very close) fee
let cp2Passed = false;
for (const p of relevantPlans) {
  if (p.scheduleType !== cheaperSchedule) continue;
  if (typeof p.estimatedMonthlyFee !== 'number') continue;
  if (Math.abs(p.estimatedMonthlyFee - cheaperFee) <= 5) {
    cp2Passed = true;
    break;
  }
}
checkpoints.push({ passed: cp2Passed, weight: 0.60 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const applications = JSON.parse(localStorage.getItem('applications') || '[]');
const preferences = JSON.parse(localStorage.getItem('application_nursery_preferences') || '[]');
const nurseries = JSON.parse(localStorage.getItem('nurseries') || '[]');

// All full-day North nurseries, sorted by rating descending
const northFull = nurseries.filter(n => n && n.district === 'north' && n.hasFullDayCare);
const northFullSorted = [...northFull].sort((a, b) => {
  const ra = typeof a.ratingAverage === 'number' ? a.ratingAverage : 0;
  const rb = typeof b.ratingAverage === 'number' ? b.ratingAverage : 0;
  return rb - ra;
});
const targetIds = northFullSorted.map(n => n.id);

// CP1 (0.40): There exists an application with careType full_day_8h_plus and districtFilter 'north' that includes at least one full-day North nursery as a preference
let cp1Passed = false;
for (const app of applications) {
  if (!app || app.careType !== 'full_day_8h_plus' || app.districtFilter !== 'north') continue;
  const appPrefs = preferences.filter(p => p.applicationId === app.id);
  const hasQual = appPrefs.some(p => {
    const n = nurseries.find(nn => nn.id === p.nurseryId);
    return n && n.district === 'north' && n.hasFullDayCare;
  });
  if (hasQual) {
    cp1Passed = true;
    break;
  }
}
checkpoints.push({ passed: cp1Passed, weight: 0.40 });

// CP2 (0.60): There exists such an application where the three full-day North nurseries are included and ordered by rating (highest as preference 1, etc.)
let cp2Passed = false;
if (northFullSorted.length >= 3) {
  const topThreeIds = northFullSorted.slice(0, 3).map(n => n.id);
  for (const app of applications) {
    if (!app || app.careType !== 'full_day_8h_plus' || app.districtFilter !== 'north') continue;
    const appPrefs = preferences.filter(p => p.applicationId === app.id);
    if (appPrefs.length < 3) continue;
    const hasAllThree = topThreeIds.every(id => appPrefs.some(p => p.nurseryId === id));
    if (!hasAllThree) continue;
    // Check preference order
    const prefByNursery = {};
    appPrefs.forEach(p => { prefByNursery[p.nurseryId] = p.preferenceOrder; });
    let ordered = true;
    for (let i = 0; i < topThreeIds.length; i++) {
      const id = topThreeIds[i];
      if (prefByNursery[id] !== i + 1) {
        ordered = false;
        break;
      }
    }
    if (ordered) {
      cp2Passed = true;
      break;
    }
  }
}
checkpoints.push({ passed: cp2Passed, weight: 0.60 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const inquiries = JSON.parse(localStorage.getItem('contact_inquiries') || '[]');
const nurseries = JSON.parse(localStorage.getItem('nurseries') || '[]');

function isQualifyingNursery(n) {
  if (!n) return false;
  if (typeof n.distanceFromHomeKm !== 'number' || n.distanceFromHomeKm > 4) return false;
  if (!n.hasNutFreeMenu) return false;
  if (!n.hasLactoseFreeOptions) return false;
  return true;
}

// Inquiries that target a qualifying nursery and use the meals/allergies subject with basic contact info
const qualifyingInquiries = inquiries.filter(i => {
  if (!i) return false;
  if (i.subject !== 'meals_allergies') return false;
  if (!i.nurseryId) return false;
  if (typeof i.parentName !== 'string' || !i.parentName.trim()) return false;
  if (typeof i.email !== 'string' || !i.email.trim()) return false;
  const n = nurseries.find(nn => nn.id === i.nurseryId);
  return isQualifyingNursery(n);
});

// CP1 (0.40): At least one meals/allergies inquiry sent to a qualifying nursery within 4 km that has both nut-free and lactose-free options, with parent name and email provided
const cp1Passed = qualifyingInquiries.length > 0;
checkpoints.push({ passed: cp1Passed, weight: 0.40 });

// Among those, check message content mentions nut and lactose
const allergyFocusedInquiries = qualifyingInquiries.filter(i => {
  const msg = (i.message || '').toLowerCase();
  return msg.includes('nut') && msg.includes('lactose');
});

// CP2 (0.30): Message explicitly mentions both nut and lactose (allergy handling focus)
const cp2Passed = allergyFocusedInquiries.length > 0;
checkpoints.push({ passed: cp2Passed, weight: 0.30 });

// CP3 (0.30): At least one such inquiry also includes a phone number for additional contact information
let cp3Passed = false;
for (const i of allergyFocusedInquiries) {
  if (typeof i.phone === 'string' && i.phone.trim().length > 0) {
    cp3Passed = true;
    break;
  }
}
checkpoints.push({ passed: cp3Passed, weight: 0.30 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const calendarDays = JSON.parse(localStorage.getItem('calendar_days') || '[]');
const applications = JSON.parse(localStorage.getItem('applications') || '[]');
const preferences = JSON.parse(localStorage.getItem('application_nursery_preferences') || '[]');
const nurseries = JSON.parse(localStorage.getItem('nurseries') || '[]');

function getDateOnly(str) {
  if (!str) return '';
  if (/^\d{4}-\d{2}-\d{2}$/.test(str)) return str;
  const d = new Date(str);
  if (isNaN(d.getTime())) return '';
  const y = d.getUTCFullYear();
  const m = String(d.getUTCMonth() + 1).padStart(2, '0');
  const day = String(d.getUTCDate()).padStart(2, '0');
  return y + '-' + m + '-' + day;
}

function parseDate(str) {
  if (!str) return null;
  const d = new Date(str);
  return isNaN(d.getTime()) ? null : d;
}

// Compute first open day after 2025-08-15
const fromDate = parseDate('2025-08-15T00:00:00Z');
let firstOpenDate = null;
calendarDays.forEach(cd => {
  if (!cd || cd.status !== 'open') return;
  const d = parseDate(cd.date);
  if (!d || !fromDate) return;
  if (d <= fromDate) return;
  const dateOnly = getDateOnly(cd.date);
  if (!firstOpenDate || dateOnly < firstOpenDate) {
    firstOpenDate = dateOnly;
  }
});

const childAgeMonths = Math.round(2 * 12); // 2-year-old

function nurseryAccepts2yo(n) {
  if (!n) return false;
  if (typeof n.acceptedAgeMinMonths === 'number' && childAgeMonths < n.acceptedAgeMinMonths) return false;
  if (typeof n.acceptedAgeMaxMonths === 'number' && childAgeMonths > n.acceptedAgeMaxMonths) return false;
  return true;
}

// Applications that use this first-open date, are full-day, and originated from the calendar
const appsWithStart = applications.filter(app => {
  if (!app) return false;
  if (!firstOpenDate) return false;
  const d = getDateOnly(app.desiredStartDate);
  if (d !== firstOpenDate) return false;
  if (app.careType !== 'full_day_8h_plus') return false;
  if (app.source !== 'calendar') return false;
  return true;
});

// CP1 (0.40): At least one calendar-sourced application uses the first open date after 2025-08-15 with full-day care
const cp1Passed = appsWithStart.length > 0;
checkpoints.push({ passed: cp1Passed, weight: 0.40 });

// CP2 (0.60): Among those, at least one application is filtered to the East district and includes an East full-day nursery that accepts a 2-year-old
let cp2Passed = false;
for (const app of appsWithStart) {
  if (app.districtFilter !== 'east') continue;
  const appPrefs = preferences.filter(p => p.applicationId === app.id);
  const hasQualPref = appPrefs.some(p => {
    const n = nurseries.find(nn => nn.id === p.nurseryId);
    return n && n.district === 'east' && n.hasFullDayCare && nurseryAccepts2yo(n);
  });
  if (hasQualPref) {
    cp2Passed = true;
    break;
  }
}
checkpoints.push({ passed: cp2Passed, weight: 0.60 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
